private JSONObject createUpdateRecordInfo(NUIForm thisForm, NUIForm updForm, RagicBundle bundle) throws JSONException {
    JSONObject info = new JSONObject();
    JSONObject actions = new JSONObject();
    JSONArray options = new JSONArray();
    JSONArray optionValues = new JSONArray();
    options.put(bundle.getString("ADD"));
    options.put(bundle.getString("SUBSTRACT"));
    options.put(bundle.getString("SET"));
    optionValues.put("ADD");
    optionValues.put("SUBSTRACT");
    optionValues.put("SET");
    actions.put("options", options);
    actions.put("optionValues", optionValues);
    info.put("actions", actions);
    
    JSONObject matchThis = new JSONObject();
    options = new JSONArray();
    optionValues = new JSONArray();
    List<CellInfo> thisCells = thisForm.getAllFields(true);
    for(CellInfo cell: thisCells) {
        String optionStr = cell.toString();
        if(thisForm.getLevel(cell.getDomainId()) > Const.SINGLE) {
        	optionStr += " (" + bundle.getString("newSubtableDefault") + " " + thisForm.getSubtableName(thisForm.getTableHeaderDomain(cell.getDomainId())) + ")";
        }
        options.put(optionStr);
        optionValues.put(cell.getDomainId());
    }
    matchThis.put("options", options);
    matchThis.put("optionValues", optionValues);
    info.put("thisField", matchThis);
    
    JSONObject matchUpd = new JSONObject();
    options = new JSONArray();
    optionValues = new JSONArray();
    List<CellInfo> updCells = updForm.getAllFields(false);
    for(CellInfo cell: updCells) {
        if(cell.getAttribute("interm") != null) continue; // issue#11057
        options.put(cell.toString());
        optionValues.put(cell.getDomainId());
    }
    matchUpd.put("options", options);
    matchUpd.put("optionValues", optionValues);
    info.put("updField", matchUpd);
    return info;
}

